sub get_deployment_version {
    my ($deployment_type) = @_;

    # Return 'unknown' for undef or empty/whitespace-only input
    return 'unknown' unless defined $deployment_type;
    $deployment_type =~ s/^\s+|\s+$//g;
    return 'unknown' if $deployment_type eq '';

    my %version_map = (
        'tobvon'       => '1.0.0-tobvon',
        'tob'          => '1.2.3-tob',
        'greenlight'   => '2.1.0-greenlight',
        'kobvon'       => '0.9.5-kobvon',
        'kob'          => '3.0.1-kob',
        'kobdflow'     => '1.5.2-kobdflow',
        'kobconnect'   => '2.0.0-kobconnect',
        'kobregistery' => '1.0.0-kobregistery',
    );

    # Normalize input to lowercase for deterministic matching
    my $key = lc $deployment_type;

    return $version_map{$key} // 'unknown';
}

