Implemented the requested utility and unit tests.

// src/utils/countWords.ts
/**
 * Count the number of words in the given input.
 * A word is defined as a sequence of one or more non-space characters separated by spaces.
 * Punctuation is considered part of words. Null/undefined/empty/whitespace-only inputs return 0.
 */
export function countWords(input: string | null | undefined): number {
  if (input == null) return 0;

  const trimmed = input.trim();
  if (trimmed.length === 0) return 0;

  // Split on one or more whitespace characters to handle multiple consecutive spaces
  return trimmed.split(/\s+/).length;
}


// test/utils/countWords.test.ts
import { strict as assert } from 'assert';
import { countWords } from '../../src/utils/countWords';

describe('countWords', () => {
  it('counts simple sentences', () => {
    assert.strictEqual(countWords("Hello world"), 2);
    assert.strictEqual(countWords("This is a sentence"), 4);
  });

  it('handles empty, whitespace-only, null, and undefined inputs', () => {
    assert.strictEqual(countWords(""), 0);
    assert.strictEqual(countWords("   "), 0);
    assert.strictEqual(countWords(null), 0);
    assert.strictEqual(countWords(undefined), 0);
  });

  it('handles leading/trailing and multiple consecutive spaces', () => {
    assert.strictEqual(countWords("  Leading and trailing  "), 3);
    assert.strictEqual(countWords("Multiple   spaces between words"), 4);
  });

  it('treats punctuation as part of words', () => {
    assert.strictEqual(countWords("Punctuation, should.be?counted!"), 1);
  });
});

Implemented a small, well-tested PHP helper that normalizes CMS category structures into a predictable shape for the frontend. Below are the two files to add to the repo: src/Utils/CategoryHelper.php and tests/Unit/CategoryHelperTest.php. The implementation preserves input order, handles objects (stdClass) and arrays, and covers edge cases (null, empty arrays, empty childs, numeric-string names).

File: src/Utils/CategoryHelper.php
<?php
/**
 * Normalize a category structure coming from the CMS into a predictable shape.
 *
 * @param array|null $input An array of category objects/arrays, each with a 'name' and 'childs' property
 * @return array Associative array with keys 'categories' and 'subCategories'
 */
function processCategories($input)
{
    // Return empty structure for null or non-array input
    if (!is_array($input)) {
        return [
            'categories' => [],
            'subCategories' => [],
        ];
    }

    $result = [
        'categories' => [],
        'subCategories' => [],
    ];

    foreach ($input as $category) {
        // Support both objects (stdClass) and associative arrays
        if (is_object($category)) {
            $name = isset($category->name) ? $category->name : null;
            $childs = isset($category->childs) ? $category->childs : [];
        } elseif (is_array($category)) {
            $name = isset($category['name']) ? $category['name'] : null;
            $childs = isset($category['childs']) ? $category['childs'] : [];
        } else {
            // Skip invalid entries
            continue;
        }

        // Preserve ordering and use the category name as the key for subCategories
        $result['categories'][] = $name;

        $subNames = [];
        if (is_array($childs)) {
            foreach ($childs as $child) {
                if (is_object($child)) {
                    $subNames[] = isset($child->name) ? $child->name : null;
                } elseif (is_array($child)) {
                    $subNames[] = isset($child['name']) ? $child['name'] : null;
                } else {
                    // If child is not object/array, append null to preserve ordering
                    $subNames[] = null;
                }
            }
        }

        // Use string cast for array key to ensure consistent keys (numeric strings preserved)
        $result['subCategories'][(string)$name] = $subNames;
    }

    return $result;
}
?>

