// format.go
package main

import (
	"strings"
)

// FormatNumberWithCommas inserts commas as thousand separators into the integer
// part of a numeric string. The input may include a leading '-' and a decimal
// part; the decimal part (if present) is left unchanged. An empty input returns
// an empty string.
func FormatNumberWithCommas(s string) string {
	// Handle empty string
	if len(s) == 0 {
		return ""
	}

	// Detect and strip leading minus sign
	negative := false
	if s[0] == '-' {
		negative = true
		s = s[1:]
	}

	// Split integer and decimal parts. Keep the dot in decimalPart so it can be
	// appended directly.
	var integerPart, decimalPart string
	if dotIndex := strings.Index(s, "."); dotIndex >= 0 {
		integerPart = s[:dotIndex]
		decimalPart = s[dotIndex:]
	} else {
		integerPart = s
	}

	var b strings.Builder
	if negative {
		b.WriteByte('-')
	}

	length := len(integerPart)
	for i := 0; i < length; i++ {
		// Insert a comma before every group of three digits, except at the
		// start of the integer part.
		if (length-i)%3 == 0 && i != 0 {
			b.WriteByte(',')
		}
		b.WriteByte(integerPart[i])
	}

	// Append the decimal part unchanged
	b.WriteString(decimalPart)

	return b.String()
}

// main is omitted on purpose; this file only provides the utility function.


