package algorithms

// SearchInsert finds the index of target in the sorted ascending slice nums,
// or returns the index where target should be inserted to maintain sorted order.
// It uses binary search and runs in O(log n) time.
func SearchInsert(nums []int, target int) int {
	left, right := 0, len(nums)-1
	for left <= right {
		mid := left + (right-left)/2
		if nums[mid] == target {
			return mid
		} else if nums[mid] < target {
			left = mid + 1
		} else {
			right = mid - 1
		}
	}
	// left is the insertion position when target is not found
	return left
}

