#' Reverse only the vowels in a string, preserving other characters and case.
#'
#' @param s A single string.
#' @return A string with vowels reversed in order; non-vowel characters remain unchanged.
#' @examples
#' reverse_vowels("leetcode") # "leotcede"
#' reverse_vowels("hello")    # "holle"
#' @export
reverse_vowels <- function(s) {
  if (!is.character(s) || length(s) != 1) {
    stop("s must be a single character string", call. = FALSE)
  }

  if (nchar(s) == 0) return(s)

  vowels <- c('a','e','i','o','u','A','E','I','O','U')
  s_chars <- strsplit(s, "", fixed = TRUE)[[1]]

  i <- 1L
  j <- length(s_chars)

  while (i < j) {
    while (i < j && !(s_chars[i] %in% vowels)) i <- i + 1L
    while (i < j && !(s_chars[j] %in% vowels)) j <- j - 1L

    if (i < j) {
      tmp <- s_chars[i]
      s_chars[i] <- s_chars[j]
      s_chars[j] <- tmp
      i <- i + 1L
      j <- j - 1L
    }
  }

  paste0(s_chars, collapse = "")
}


