// src/utils/grades.ts
/**
 * determineGrade(score)
 *
 * Map a numeric score to a letter grade.
 * - Returns 'A' for scores >= 90
 * - Returns 'B' for scores 80..89
 * - Returns 'C' for scores 70..79
 * - Returns 'D' for scores 60..69
 * - Returns 'E' for scores 0..59
 * - Returns 'Invalid' for non-number inputs or values < 0 or > 100
 *
 * The function accepts any input type, validates it, and returns one of
 * the exact strings: 'A','B','C','D','E', or 'Invalid'.
 */
export function determineGrade(score: any): string {
  // Ensure the input is a number and not NaN
  if (typeof score !== 'number' || Number.isNaN(score)) {
    return 'Invalid';
  }

  // Reject out-of-range numbers
  if (score < 0 || score > 100) {
    return 'Invalid';
  }

  if (score >= 90) return 'A';
  if (score >= 80) return 'B';
  if (score >= 70) return 'C';
  if (score >= 60) return 'D';
  return 'E';
}

// test/grades.test.ts
import { strict as assert } from 'assert';
import { determineGrade } from '../src/utils/grades';

// Minimal required demo test function
export const demoTesting = () => {
  assert.strictEqual(determineGrade(85), 'B');
  assert.strictEqual(determineGrade(45), 'E');
};

// Comprehensive unit tests covering boundaries and invalid inputs
export const runAllTests = () => {
  // Boundaries and typical values
  assert.strictEqual(determineGrade(0), 'E');
  assert.strictEqual(determineGrade(59), 'E');
  assert.strictEqual(determineGrade(60), 'D');
  assert.strictEqual(determineGrade(69), 'D');
  assert.strictEqual(determineGrade(70), 'C');
  assert.strictEqual(determineGrade(79), 'C');
  assert.strictEqual(determineGrade(80), 'B');
  assert.strictEqual(determineGrade(89), 'B');
  assert.strictEqual(determineGrade(90), 'A');
  assert.strictEqual(determineGrade(100), 'A');

  // Invalid numeric ranges
  assert.strictEqual(determineGrade(-1), 'Invalid');
  assert.strictEqual(determineGrade(101), 'Invalid');

  // Non-number inputs
  assert.strictEqual(determineGrade(null), 'Invalid');
  assert.strictEqual(determineGrade('95'), 'Invalid');
  assert.strictEqual(determineGrade(undefined), 'Invalid');
  assert.strictEqual(determineGrade(NaN), 'Invalid');

  // Optional: extreme numeric values
  assert.strictEqual(determineGrade(Infinity), 'Invalid');
  assert.strictEqual(determineGrade(-Infinity), 'Invalid');
};

// If running this file directly with ts-node or similar, run tests
