sub calculate_fan_speed {
    my ($current_temp, $previous_temp) = @_;
    # Use the higher of the two readings
    my $t = $current_temp > $previous_temp ? $current_temp : $previous_temp;

    # For temps >= 33 the fan increases by 2 per degree: fan = 2*t - 56.
    # For temps <= 32 use base speed 8.
    return ($t >= 33) ? (2 * $t - 56) : 8;
}

Solution overview:

We can separate the x and y coordinates because the Manhattan sum splits: for any integer (x,y) the total distance is Sx(x) + Sy(y) where Sx(x) = sum_i |x - x_i| and Sy(y) = sum_i |y - y_i|. For a fixed x, the y values that satisfy Sy(y) <= D - Sx(x) form a contiguous integer interval (possibly empty) because Sy(y) is convex (V-shaped) with a single minimum. Thus the algorithm is:

1. Build arrays Sx over all integer x in [min_x - D, max_x + D] and Sy over all integer y in [min_y - D, max_y + D]. Outside those ranges Sx or Sy > D, so points cannot qualify.
2. For each integer x in that x-range with Sx <= D, compute t = D - Sx and find how many y in the y-range satisfy Sy <= t. Because Sy is convex, locate the minimum position m_y and use two binary searches (one on the left nonincreasing part, one on the right nondecreasing part) to get the leftmost and rightmost y indices with Sy <= t. Add the interval length to the answer.

Complexity: sorting coordinates is O(N log N). Building Sx and Sy takes O(range_x + range_y + N) using a sweep with a pointer and the slope trick (S(x+1) = S(x) + 2*count_le - N). The per-x binary searches cost O(log range_y) and are only performed for x with Sx <= D. For the constraints given (coordinate bounds ±1e6, D ≤ 1e6) this is practical and memory/time efficient in C++.

C++ implementation (single-file CLI reading stdin, writing stdout):

#include <bits/stdc++.h>
using namespace std;
using int64 = long long;

// Build S array for integer positions from L..R inclusive where S[pos-L] = sum |pos - arr[i]|
// arr must be sorted.
vector<int64> buildS(const vector<int>& arr, int L, int R) {
    int n = (int)arr.size();
    int len = R - L + 1;
    vector<int64> S;
    S.reserve(len);

    // compute S at pos = L
    int64 s = 0;
    for (int v: arr) s += (int64)abs((int64)v - (int64)L);
    S.push_back(s);

    int p = 0; // number of arr elements <= current x
    for (int i = 0; i < n && arr[i] <= L; ++i) ++p;

    for (int pos = L; pos < R; ++pos) {
        // slope trick: S(pos+1) = S(pos) + 2*p - n
        s += (int64)2*p - n;
        // advance p for new pos+1
        while (p < n && arr[p] <= pos+1) ++p;
        S.push_back(s);
    }
    return S;
}

// Find smallest index in [0..m] such that S[idx] <= t. S[0..m] is nonincreasing toward m.
int find_left_le(const vector<int64>& S, int m, int64 t) {
    int lo = 0, hi = m; // inclusive
    int ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        if (S[mid] <= t) {
            ans = mid;
            hi = mid - 1; // look for smaller index
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

// Find largest index in [m..len-1] such that S[idx] <= t. S[m..end] is nondecreasing away from m.
int find_right_le(const vector<int64>& S, int m, int64 t) {
    int lo = m, hi = (int)S.size() - 1;
    int ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        if (S[mid] <= t) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    long long D;
    if (!(cin >> N >> D)) return 0;
    vector<int> xs(N), ys(N);
    int minx = INT_MAX, maxx = INT_MIN, miny = INT_MAX, maxy = INT_MIN;
    for (int i = 0; i < N; ++i) {
        cin >> xs[i] >> ys[i];
        minx = min(minx, xs[i]);
        maxx = max(maxx, xs[i]);
        miny = min(miny, ys[i]);
        maxy = max(maxy, ys[i]);
    }

    // Determine ranges where Sx or Sy could be <= D
    int Lx = minx - (int)D;
    int Rx = maxx + (int)D;
    int Ly = miny - (int)D;
    int Ry = maxy + (int)D;

    // sort copies
    vector<int> xs_sorted = xs;
    vector<int> ys_sorted = ys;
    sort(xs_sorted.begin(), xs_sorted.end());
    sort(ys_sorted.begin(), ys_sorted.end());

    // Build Sx and Sy arrays
    vector<int64> Sx = buildS(xs_sorted, Lx, Rx);
    vector<int64> Sy = buildS(ys_sorted, Ly, Ry);

    // find index of minimum in Sy (any minimum position)
    int m_y = 0;
    for (int i = 1; i < (int)Sy.size(); ++i) {
        if (Sy[i] < Sy[m_y]) m_y = i;
    }

    // For each x with Sx <= D, count number of y with Sy <= D - Sx
    long long answer = 0;
    int lenY = Ry - Ly + 1;
    for (int ix = 0; ix < (int)Sx.size(); ++ix) {
        int64 sx = Sx[ix];
        if (sx > D) continue;
        int64 t = D - sx;
        if (Sy[m_y] > t) continue; // no y
        int left = find_left_le(Sy, m_y, t);
        int right = find_right_le(Sy, m_y, t);
        if (left != -1 && right != -1 && right >= left) answer += (right - left + 1);
    }

    cout << answer << '\n';
    return 0;
}

