func findMinWeightDifference(_ weights: [Int]) -> Int {
    // Empty array: by requirement, return 0
    guard !weights.isEmpty else { return 0 }

    // Total sum of all weights
    let total = weights.reduce(0, +)

    // Dynamic programming over reachable subset sums.
    // This handles negative, zero and positive weights uniformly.
    // reachable holds all sums that can be formed by choosing some subset of processed weights.
    var reachable: Set<Int> = [0]
    for w in weights {
        var next = reachable
        for s in reachable {
            next.insert(s + w)
        }
        reachable = next
    }

    // Find the subset sum s that minimizes |total - 2*s|.
    var minDiff = Int.max
    for s in reachable {
        let diff = abs(total - 2 * s)
        if diff < minDiff {
            minDiff = diff
            if minDiff == 0 { break } // early exit if perfect balance found
        }
    }

    return minDiff
}

