function isValidParentheses(s) {
    // Map opening brackets to their corresponding closing brackets
    const brackets = {
        '(': ')',
        '{': '}',
        '[': ']'
    };

    // Set of closing brackets for quick checks
    const closing = new Set(Object.values(brackets));

    const stack = [];

    for (const char of s) {
        // If it's an opening bracket, push the expected closing bracket
        if (brackets[char]) {
            stack.push(brackets[char]);
        }
        // If it's a closing bracket, it must match the top of the stack
        else if (closing.has(char)) {
            if (stack.pop() !== char) {
                return false;
            }
        }
        // Otherwise ignore non-bracket characters
    }

    // All brackets must be closed
    return stack.length === 0;
}

module.exports = { isValidParentheses };


