// hasBalancedParentheses.js
// Utility to check whether parentheses in a string are balanced.
// Considers only: (), {}, [] and ignores all other characters.

const hasBalancedParentheses = (str) => {
    const stack = [];
    const pairs = {
        '(': ')',
        '{': '}',
        '[': ']'
    };
    const closing = new Set([')', '}', ']']);

    for (const char of str) {
        if (pairs[char]) {
            // opening bracket
            stack.push(char);
        } else if (closing.has(char)) {
            // closing bracket
            if (stack.length === 0) return false;
            const lastOpen = stack.pop();
            if (pairs[lastOpen] !== char) return false;
        }
        // ignore all other characters
    }

    return stack.length === 0;
};

// Export if running in a module environment (optional)
if (typeof module !== 'undefined' && module.exports) {
    module.exports = hasBalancedParentheses;
}

