const demoTesting = () => {
    assert.strictEqual(hasBalancedParentheses('((()))'), true);
    assert.strictEqual(hasBalancedParentheses('(()())'), true);
};

const runAdditionalTests = () => {
    // empty string is balanced
    assert.strictEqual(hasBalancedParentheses(''), true);

    // mixed balanced cases
    assert.strictEqual(hasBalancedParentheses('{[()]}'), true);
    assert.strictEqual(hasBalancedParentheses('{[]()}'), true);

    // incorrect nesting
    assert.strictEqual(hasBalancedParentheses('{[}]'), false);

    // unmatched open
    assert.strictEqual(hasBalancedParentheses('((('), false);

    // unmatched close
    assert.strictEqual(hasBalancedParentheses('())'), false);

    // other characters interleaved
    assert.strictEqual(hasBalancedParentheses('function(){ return [1,2,3]; }'), true);
    assert.strictEqual(hasBalancedParentheses('var a = [1,2,3;'), false);

    // no parentheses at all
    assert.strictEqual(hasBalancedParentheses('hello world'), true);

    // closing without opening
    assert.strictEqual(hasBalancedParentheses(']'), false);
};

