calculate_min_sugar_bags <- function(n) {
  # Validate input: n must be an integer in [0, 500]
  if (!is.numeric(n) || length(n) != 1 || n < 0 || n > 500 || n != as.integer(n)) {
    stop('n must be an integer between 0 and 500')
  }
  n <- as.integer(n)

  # Zero kilograms requires zero bags
  if (n == 0L) return(0L)

  # If divisible by 5, using only 5kg bags minimizes the number of bags
  if (n %% 5L == 0L) return(n %/% 5L)

  # Otherwise try increasing counts of 3kg bags (this maximizes the use of 5kg bags
  # and thus minimizes the total number of bags when a solution exists)
  max_3kg <- n %/% 3L
  for (i in seq_len(max_3kg)) {
    remaining <- n - i * 3L
    if (remaining >= 0L && remaining %% 5L == 0L) {
      return(i + (remaining %/% 5L))
    }
  }

  # No combination of 3kg and 5kg bags makes exactly n kg
  return(-1L)
}

