export interface GreetOptions {
  greeting?: string;
  punctuation?: string;
  defaultName?: string;
}

export function enhancedGreet(name: any, options: GreetOptions = {}): string {
  const { greeting = 'Hello', punctuation = '!', defaultName = 'Guest' } = options;

  let finalName: string;

  if (name === undefined || name === null) {
    finalName = defaultName;
  } else {
    // Convert to string and trim whitespace
    finalName = String(name).trim();
    if (finalName === '') {
      finalName = defaultName;
    }
  }

  return `${greeting} ${finalName}${punctuation}`;
}


