// fizzBuzz.js
function fizzBuzz(input) {
  // Only values whose typeof is "number" are processed. Other types return the exact error string.
  if (typeof input !== 'number') {
    return "Error: Input must be a number";
  }

  // For numeric inputs, follow divisibility semantics.
  // Use modulo checks; decimals that are not evenly divisible will fall through to the numeric string.
  if (input % 3 === 0 && input % 5 === 0) {
    return "FizzBuzz";
  }
  if (input % 3 === 0) {
    return "Fizz";
  }
  if (input % 5 === 0) {
    return "Buzz";
  }

  return String(input);
}

module.exports = fizzBuzz;


