# Implementation of countGoodPartitions(nums)
# Counts the number of ways to partition the array into contiguous subarrays
# such that no integer value appears in more than one chosen subarray.
# Key observation:
#   For each value v, let last[v] be the last index where v appears. A cut
#   between indices i and i+1 is allowed iff no value that has appeared in
#   positions 0..i has last occurrence > i. While scanning left-to-right we
#   maintain max_last = max(last[nums[j]] for j <= i). A cut is allowed at i
#   exactly when max_last == i. The number of good partitions is 2^(number_of_allowed_cuts).
# Complexity: O(n) time, O(n) extra space.

from typing import List
import unittest

MOD = 10**9 + 7

def countGoodPartitions(nums: List[int]) -> int:
    n = len(nums)
    if n <= 1:
        return 1

    # Compute last occurrence of each value
    last = {}
    for i, v in enumerate(nums):
        last[v] = i

    cuts = 0
    max_last = -1
    for i, v in enumerate(nums):
        # update the furthest last occurrence among values seen so far
        if last[v] > max_last:
            max_last = last[v]
        # if the furthest last occurrence is exactly i, it's safe to cut after i
        if max_last == i and i < n - 1:
            cuts += 1

    return pow(2, cuts, MOD)


# Unit tests covering the examples and edge cases
class TestCountGoodPartitions(unittest.TestCase):
    def test_examples(self):
        self.assertEqual(countGoodPartitions([1,2,3,4]), 8)  # 2^(n-1) = 8
        self.assertEqual(countGoodPartitions([1,1,1,1]), 1)  # no valid cuts
        self.assertEqual(countGoodPartitions([1,2,1,3]), 2)

    def test_single_element(self):
        self.assertEqual(countGoodPartitions([5]), 1)

    def test_all_distinct(self):
        self.assertEqual(countGoodPartitions([10,20,30,40,50]), pow(2,4,MOD))

    def test_repeated_various_positions(self):
        # Value 1 occurs in indices 0..1, value 2 in indices 2..4, value 3 at 3
        self.assertEqual(countGoodPartitions([1,1,2,3,2]), 2)

    def test_no_cut_possible(self):
        # Single value spanning whole array
        self.assertEqual(countGoodPartitions([7,7,7,7,7]), 1)

    def test_many_allowed_cuts(self):
        # Partition points at every position
        arr = [i for i in range(1, 11)]  # all distinct of length 10
        self.assertEqual(countGoodPartitions(arr), pow(2, 9, MOD))


