/**
 * Classify an input token for the in-app calculator.
 * Returns true for values that should NOT be treated as operators (i.e., numeric/decimal tokens
 * or other allowed tokens per requirements). Returns false for operator tokens or invalid numeric tokens.
 *
 * Rules (exact):
 * - Accepts any JS value as input.
 * - Returns a strict boolean.
 * - Returns true for: number types (finite), numeric strings, 
 *   the decimal point ("."), the equals sign ("="), an empty string (""), booleans, null,
 *   whitespace-only strings, and strings composed solely of digits and decimal points.
 * - Returns false for: operators (e.g. "+"), non-numeric strings (e.g. "abc"), undefined,
 *   and strings containing operator characters (e.g. "5+5").
 */
function isOperator(input: any): boolean {
  // undefined is considered an operator/invalid numeric token per requirements
  if (input === undefined) {
    return false;
  }

  // null and booleans are explicitly non-operator tokens
  if (input === null) {
    return true;
  }
  if (typeof input === 'boolean') {
    return true;
  }

  // numeric types: accept finite numbers
  if (typeof input === 'number') {
    return Number.isFinite(input);
  }

  // strings: several allowed cases
  if (typeof input === 'string') {
    // empty string or whitespace-only string => true
    if (input === '' || input.trim() === '') {
      return true;
    }

    // explicit single-character tokens allowed
    if (input === '.' || input === '=') {
      return true;
    }

    // string composed solely of digits and decimal points (after trimming)
    const trimmed = input.trim();
    if (/^[0-9.]+$/.test(trimmed)) {
      return true;
    }

    // any other string (contains letters, operators, mixed tokens) => false
    return false;
  }

  // all other types (objects, symbols, functions, etc.) are treated as operators/invalid
  return false;
}

