// Multiply returns the product of num1 and num2 where each input is a
// decimal representation of a non-negative integer. The function does not
// use any big-integer libraries or convert the entire input into native
// integers; it performs digit-wise multiplication and works for
// arbitrarily long inputs.
//
// Rules applied:
// - Empty input strings are treated as "0".
// - Leading zeros are stripped before computation (e.g. "0123" -> "123").
// - The returned result has no leading zeros unless it is exactly "0".
func Multiply(num1, num2 string) string {
	// Treat empty strings as "0"
	if num1 == "" {
		num1 = "0"
	}
	if num2 == "" {
		num2 = "0"
	}

	// Strip leading zeros
	num1 = strings.TrimLeft(num1, "0")
	num2 = strings.TrimLeft(num2, "0")

	// If after trimming we get empty, it's zero
	if num1 == "" {
		num1 = "0"
	}
	if num2 == "" {
		num2 = "0"
	}

	// Quick return if either is zero
	if num1 == "0" || num2 == "0" {
		return "0"
	}

	m, n := len(num1), len(num2)
	// result digits, max length m+n
	res := make([]int, m+n)

	// Multiply like elementary school arithmetic from right to left
	for i := m - 1; i >= 0; i-- {
		a := int(num1[i] - '0')
		for j := n - 1; j >= 0; j-- {
			b := int(num2[j] - '0')
			posLow := i + j + 1
			posHigh := i + j
			res[posLow] += a * b
			// carry immediately to keep values small
			res[posHigh] += res[posLow] / 10
			res[posLow] = res[posLow] % 10
		}
	}

	// Skip leading zeros in the result
	idx := 0
	for idx < len(res) && res[idx] == 0 {
		idx++
	}

	// Build string
	var sb strings.Builder
	for ; idx < len(res); idx++ {
		sb.WriteByte(byte(res[idx] + '0'))
	}

	return sb.String()
}

