package Utils::PackageCheck;

use strict;
use warnings;
use Exporter 'import';

our @EXPORT_OK = qw(is_package_installed);
our $VERSION   = '0.01';

# is_package_installed($pkg_name) -> 1 if installed, 0 otherwise
# - Returns 0 for undefined/empty/invalid package names
# - Does not print to STDOUT or STDERR
sub is_package_installed {
    my ($pkg) = @_;

    # Requirement 4: handle empty/invalid package names by returning 0
    return 0 unless defined $pkg;
    $pkg =~ s/^\s+|\s+$//g;
    return 0 if $pkg eq '';
    # Basic validity check: no whitespace or control chars
    return 0 if $pkg =~ /[\s\x00-\x1f\x7f]/;

    # Debian/Ubuntu: parse /var/lib/dpkg/status if present (avoids calling external command)
    if ( -r '/var/lib/dpkg/status' ) {
        if (open my $fh, '<', '/var/lib/dpkg/status') {
            local $/ = "\n";
            while (my $line = <$fh>) {
                # look for lines like: "Package: <name>"
                if ($line =~ /^Package:\s+(\S+)/) {
                    return 1 if $1 eq $pkg;
                }
            }
            close $fh;
            return 0;
        }
        # If the status file exists but cannot be read, fall through to other checks
    }

    # RPM-based systems: use rpm -q <pkg> and capture output (redirect stderr)
    # We use shell redirection to suppress any stderr to satisfy the no-output requirement.
    if ( -x '/bin/rpm' || -x '/usr/bin/rpm' ) {
        # qx// with stderr redirected so the function does not emit to STDERR
        my $out = qx{rpm -q --quiet --whatprovides --qf "%{NAME}\n" -- "$pkg" 2>/dev/null};
        # If output contains the package name on a line, consider it installed
        if (defined $out && $out =~ /^\Q$pkg\E\s*$/m) {
            return 1;
        }
        # rpm -q may succeed with alternate names; also try the simpler query
        my $simple = qx{rpm -q --quiet -- "$pkg" 2>/dev/null};
        return 1 if $simple eq '' && $? == 0; # rpm returns 0 on success but with --quiet no output
        return 0;
    }

    # snap (optional): try 'snap list' if available (suppress stderr)
    if ( -x '/usr/bin/snap' || -x '/snap/bin/snap' ) {
        my $snap_out = qx{snap list 2>/dev/null};
        if (defined $snap_out) {
            for my $line (split /\n/, $snap_out) {
                next if $line =~ /^Name\s+/;    # header line
                if ($line =~ /^\Q$pkg\E\s+/) {
                    return 1;
                }
            }
        }
    }

    # Fallback: not found
    return 0;
}

1;

