#include <bits/stdc++.h>
using namespace std;

using cd = complex<double>;
const double PI = acos(-1);

void fft(vector<cd> & a, bool invert) {
    int n = a.size();
    for (int i = 1, j = 0; i < n; ++i) {
        int bit = n >> 1;
        for (; j & bit; bit >>= 1)
            j ^= bit;
        j ^= bit;
        if (i < j) swap(a[i], a[j]);
    }

    for (int len = 2; len <= n; len <<= 1) {
        double ang = 2 * PI / len * (invert ? -1 : 1);
        cd wlen(cos(ang), sin(ang));
        for (int i = 0; i < n; i += len) {
            cd w(1);
            for (int j = 0; j < len/2; ++j) {
                cd u = a[i+j];
                cd v = a[i+j+len/2] * w;
                a[i+j] = u + v;
                a[i+j+len/2] = u - v;
                w *= wlen;
            }
        }
    }

    if (invert) {
        for (cd & x : a) x /= n;
    }
}

vector<long long> convolution(const vector<int> &a) {
    int n = a.size();
    int need = 1;
    while (need < n + n) need <<= 1;
    vector<cd> fa(need);
    for (int i = 0; i < n; ++i) fa[i] = cd(a[i], 0);
    for (int i = n; i < need; ++i) fa[i] = cd(0,0);

    fft(fa, false);
    for (int i = 0; i < need; ++i) fa[i] *= fa[i];
    fft(fa, true);

    vector<long long> result(2*n);
    for (int i = 0; i < 2*n && i < (int)fa.size(); ++i)
        result[i] = (long long) llround(fa[i].real());
    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    if (!(cin >> N)) return 0;
    vector<int> S(N);
    int maxv = 0;
    for (int i = 0; i < N; ++i) {
        cin >> S[i];
        if (S[i] > maxv) maxv = S[i];
    }

    int V = maxv;
    // presence array of size V+1 (0 unused)
    vector<int> present(V+1, 0);
    for (int x : S) present[x] = 1;

    // convolve present with itself
    vector<long long> conv = convolution(present);
    // conv[k] = number of ordered pairs (i,j) with i+j = k

    long long ans = 0;
    for (int b : S) {
        int idx = 2*b;
        if (idx < (int)conv.size()) {
            long long val = conv[idx];
            // subtract the (b,b) term, because (b,b) corresponds to A=B=C and is invalid
            // present[b] is 1 because b is in S
            val -= 1;
            if (val > 0) ans += val / 2; // each unordered pair counted twice
        }
    }

    cout << ans << '\n';
    return 0;
}


README
======
Language: C++17

Description
-----------
Command-line program that reads a set S of distinct positive integers and prints the number of ordered triplets (A, B, C) where A < B < C, A, B, C ∈ S and B - A = C - B (i.e., they form an arithmetic progression).

Build
-----
Requires a C++17-capable compiler.

Example build command:
  g++ -O2 -std=c++17 -march=native -o fine_triplets fine_triplets.cpp

Run
---
The program reads from stdin and writes a single integer to stdout.

Example:
  echo -e "5\n8 3 1 5 2" | ./fine_triplets
  # prints: 3

Complexity
----------
Let V be the maximum value in S (V <= 1e6), and N be the number of elements (N <= 1e6).
- We create a presence array of size V+1: O(V) memory.
- We compute the convolution of the presence array with itself using FFT on length L = next power of two >= 2*(V+1): time O(L log L) = O(V log V).
- The final aggregation iterates over N elements: O(N).
Overall time: O(V log V + N). Memory: O(L) ~ O(V).
This meets the performance requirements for V, N up to 1e6 on typical modern hardware.

Correctness notes
-----------------
- The convolution conv[k] gives the number of ordered pairs (i, j) in S with i + j == k.
- For a candidate middle element B ∈ S, valid pairs (A, C) satisfying A + C == 2*B are counted in conv[2*B].
- conv[2*B] includes the (B,B) pair; subtract 1 to exclude this invalid case.
- Each unordered (A, C) with A != C contributes two ordered pairs, so we divide by 2.
- Summing (conv[2*B] - 1) / 2 over B ∈ S yields the number of (A,B,C) with A < B < C and A+C=2B.

Tests and example runs
----------------------
Sample 1:
Input:
5
8 3 1 5 2

Run:
  echo -e "5\n8 3 1 5 2" | ./fine_triplets
Output:
3

Sample 2:
Input:
7
300000 100000 499998 499999 200000 400000 500000

Run:
  echo -e "7\n300000 100000 499998 499999 200000 400000 500000" | ./fine_triplets
Output:
5

Sample 3:
Input:
10
13 1 16 15 12 4 7 10 2 19

Run:
  echo -e "10\n13 1 16 15 12 4 7 10 2 19" | ./fine_triplets
Output:
10

Stress test (suggested)
-----------------------
To validate performance at the upper bounds:
- Generate S = {1, 2, 3, ..., 1000000} (N = 1e6, V = 1e6). This is a worst-case dense input.
- Command to generate and run (on a system with enough memory):
    seq 1 1000000 | xargs | sed -e 's/^/1000000\n/' | ./fine_triplets
  or use a small generator program that prints N then N numbers.

Expected behavior: program completes within a reasonable time (seconds to tens of seconds depending on hardware) and memory usage within a few hundred MB (FFT arrays dominate memory).

Notes
-----
- This implementation uses a double-precision FFT. For the problem sizes indicated (presence values 0/1 and convolution values within integer ranges), rounding errors are not expected to affect correctness if compiled with optimization. We round convolution results before final counting.
- If absolute determinism without fp rounding is required, an integer NTT-based implementation modulo a suitable prime can be used; that increases implementation complexity.

