// Exports a single function: countUniqueBSTs(n)
// Computes the number of structurally unique BSTs with n nodes (Catalan numbers).

function countUniqueBSTs(n) {
  // Validate input
  if (!Number.isInteger(n)) {
    throw new TypeError('Input must be an integer');
  }

  // Requirement: If n is negative, return 0
  if (n < 0) return 0;

  // n == 0 -> one empty tree
  if (n === 0) return 1;

  // Enforce documented valid range
  if (n > 10000) {
    throw new RangeError('n must be at most 10000');
  }

  // Use BigInt arithmetic and the multiplicative formula for binomial coefficients:
  // Catalan(n) = binom(2n, n) / (n + 1)
  // Compute binom(2n, n) as product_{i=1..n} (n + i)/i using BigInt to avoid precision loss.

  let binom = 1n;
  const bigN = BigInt(n);

  for (let i = 1; i <= n; i++) {
    // Multiply by (n + i)
    binom = binom * BigInt(n + i) / BigInt(i);
    // The division is exact at each step because the intermediate product computes integer binomial progressively.
  }

  const catalan = binom / (bigN + 1n);

  // For convenience and compatibility with existing tests, return a Number when the result fits safely
  // in JavaScript's Number (<= Number.MAX_SAFE_INTEGER). Otherwise return a BigInt.
  const MAX_SAFE = BigInt(Number.MAX_SAFE_INTEGER);
  if (catalan <= MAX_SAFE) return Number(catalan);
  return catalan;
}

module.exports = countUniqueBSTs;


