// Assumptions:
// - Input to Base10ToBase62 is an int64 that can be 0 or a positive integer.
// - For negative inputs to Base10ToBase62, the function returns nil and MapIndexes will return an empty string.
// - MapIndexes expects each byte to be in the range 0..61. If any byte is >= 62, it returns "ALPHABET overflow".
// - The base-62 digits returned by Base10ToBase62 are in most-significant-digit first order.

const ALPHABET = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"

// Base10ToBase62 converts an int64 number to a base-62 digit slice (most-significant-digit first).
// Signature must remain: func Base10ToBase62(n int64) []byte
func Base10ToBase62(n int64) []byte {
	if n < 0 {
		// Per requirement: negative inputs should lead to MapIndexes returning an empty string.
		// Returning nil here allows MapIndexes to detect the negative case.
		return nil
	}

	if n == 0 {
		return []byte{0}
	}

	var digits []byte
	for n > 0 {
		remainder := n % 62
		digits = append(digits, byte(remainder)) // LSB-first
		n = n / 62
	}

	// Reverse to make most-significant-digit first
	reverse(digits)
	return digits
}

// MapIndexes maps each byte (0..61) to the character defined by ALPHABET.
// Signature must remain: func MapIndexes(digits []byte) string
// Special cases:
// - If digits == nil, return empty string (used to indicate negative input handled by Base10ToBase62).
// - If any byte value >= 62, return "ALPHABET overflow".
func MapIndexes(digits []byte) string {
	if digits == nil {
		return ""
	}

	var b strings.Builder
	for _, d := range digits {
		if int(d) >= len(ALPHABET) {
			return "ALPHABET overflow"
		}
		b.WriteByte(ALPHABET[d])
	}
	return b.String()
}

// helper to reverse a byte slice in place
func reverse(s []byte) {
	for i, j := 0, len(s)-1; i < j; i, j = i+1, j-1 {
		s[i], s[j] = s[j], s[i]
	}
}

