package coremath

import (
	"math"
)

// Divide performs deterministic 32-bit integer division according to the following rules:
// 1. Performs normal integer division for positive and negative inputs.
// 2. If divisor == 0, returns math.MaxInt32.
// 3. If dividend == math.MinInt32 and divisor == -1, returns math.MaxInt32 (to avoid overflow).
// 4. Otherwise returns the truncated integer quotient (rounded toward zero).
//
// The function signature is exactly: func Divide(dividend int, divisor int) int
func Divide(dividend int, divisor int) int {
	// Handle special/overflow cases first
	if divisor == 0 || (dividend == math.MinInt32 && divisor == -1) {
		return math.MaxInt32
	}

	// Use int64 to safely take absolute values without overflow
	dvd := abs(int64(dividend))
	dvs := abs(int64(divisor))
	var result int64

	// Perform division using subtraction and bit shifts (fast repeated subtraction)
	for dvd >= dvs {
		tmp := dvs
		multiple := int64(1)
		for dvd >= (tmp << 1) {
			tmp <<= 1
			multiple <<= 1
		}
		dvd -= tmp
		result += multiple
	}

	// Apply sign: if dividend and divisor have same sign, result is positive
	if (dividend > 0) == (divisor > 0) {
		return int(result)
	}
	return -int(result)
}

func abs(n int64) int64 {
	if n < 0 {
		return -n
	}
	return n
}

