// sumSquaredDifferences.swift
// Generic, O(n) iterative implementation that preserves input numeric type (Int or Double).
// Signature choice: a single generic function using the Numeric protocol so the return
// type matches the input element type. This keeps integer inputs returning Int and
// floating inputs returning Double, satisfying deterministic behavior requirements.

import Foundation

/// Compute the sum of squared differences between consecutive elements.
///
/// For an input [x0, x1, x2, ...], this returns sum((x_{i+1} - x_i)^2) for i = 0..n-2.
/// If the array has fewer than two elements, returns 0 of the element type.
///
/// - Parameter data: An array of numeric values (Int, Double, etc.).
/// - Returns: The sum of squared consecutive differences as the same numeric type.
///
/// Complexity: O(n) time, O(1) extra space.
func sumSquaredDifferences<T: Numeric>(_ data: [T]) -> T {
    let n = data.count
    guard n >= 2 else { return .zero }

    var sum: T = .zero
    for i in 0..<(n - 1) {
        let diff = data[i + 1] - data[i]
        sum += diff * diff
    }
    return sum
}

