// SequenceNormalizer.java
// Production-ready implementation for the core algorithms team's sequence-normalization utility.
// Method signature required: int minimizeMaxAdjacentDifference(int[] nums)
// Behavior: Replace every -1 in nums with either x or y (a single chosen pair (x,y) used globally),
// to minimize the maximum absolute difference between adjacent elements. Returns that minimal maximum.

import java.util.*;

public class SequenceNormalizer {

    /**
     * Compute the minimal possible maximum absolute difference between adjacent elements
     * after replacing every -1 in nums with either x or y (x and y chosen once globally).
     *
     * Time complexity: O(n). Space complexity: O(1).
     *
     * Rationale / correctness:
     * - Let curMax be the maximum absolute difference among adjacent pairs that contain no -1.
     * - For each -1 that is adjacent to a known value v, collect all such v into a set summarized
     *   by low = min(v) and high = max(v). Any replacement values x,y must make |x - v| and |y - v|
     *   small for those v. The minimal worst-case impact from these neighbors is ceil((high - low)/2).
     * - If there are no known neighbors (all positions are -1), we can pick any single value for all
     *   entries and achieve 0.
     * - The answer is max(curMax, ceil((high - low)/2)). This matches the requirement that we may
     *   choose two values and assign each -1 to either, which allows constructing values near the
     *   midpoint between low and high.
     */
    public static int minimizeMaxAdjacentDifference(int[] nums) {
        int n = nums.length;
        if (n < 2) return 0; // by constraints n >= 2, but safe-guard

        int curMax = 0;
        boolean hasMissing = false;
        int low = Integer.MAX_VALUE; // min neighbor value adjacent to a -1
        int high = Integer.MIN_VALUE; // max neighbor value adjacent to a -1

        for (int i = 0; i < n - 1; i++) {
            int a = nums[i];
            int b = nums[i + 1];

            if (a == -1 || b == -1) {
                hasMissing = true;
            }

            if (a != -1 && b != -1) {
                curMax = Math.max(curMax, Math.abs(a - b));
            }

            if (a == -1 && b != -1) {
                low = Math.min(low, b);
                high = Math.max(high, b);
            }
            if (a != -1 && b == -1) {
                low = Math.min(low, a);
                high = Math.max(high, a);
            }
        }

        if (!hasMissing) {
            // No replacements needed
            return curMax;
        }

        if (low == Integer.MAX_VALUE) {
            // All elements are -1 (no known neighbors): we can set all to same value => 0
            return 0;
        }

        int needed = (high - low + 1) / 2; // ceil((high - low) / 2)
        return Math.max(curMax, needed);
    }

    // -------------------- Unit tests --------------------
    // Simple test runner to validate acceptance criteria and edge cases.
    public static void main(String[] args) {
        runTests();
    }

    private static void assertEq(int got, int want, String caseName) {
        if (got != want) {
            throw new AssertionError(caseName + " failed: got=" + got + " want=" + want);
        } else {
            System.out.println(caseName + " passed.");
        }
    }

    private static void runTests() {
        // Examples
        assertEq(minimizeMaxAdjacentDifference(new int[]{1, 2, -1, 10, 8}), 4, "Example 1");
        assertEq(minimizeMaxAdjacentDifference(new int[]{-1, -1, -1}), 0, "Example 2");
        assertEq(minimizeMaxAdjacentDifference(new int[]{-1, 10, -1, 8}), 1, "Example 3");

        // Edge cases
        // No missing values
        assertEq(minimizeMaxAdjacentDifference(new int[]{5, 2, 9, 7}), Math.max(Math.abs(5-2), Math.max(Math.abs(2-9), Math.abs(9-7))), "No missing");
        // Missing values only at one end
        assertEq(minimizeMaxAdjacentDifference(new int[]{-1, -1, 5, 8}), 0 >= 0 ? 3 : 3, "Missing at start"); // expected: max(curMax=3, ceil((8-5)/2)=2) => 3
        assertEq(minimizeMaxAdjacentDifference(new int[]{5, 8, -1, -1}), 3, "Missing at end");
        // Missing values in middle between same neighbors
        assertEq(minimizeMaxAdjacentDifference(new int[]{10, -1, -1, 10}), 0, "Missing middle same neighbors");
        // Large values and large n performance is not run here, but ensure function handles big numbers
        int[] big = new int[100000];
        Arrays.fill(big, -1);
        assertEq(minimizeMaxAdjacentDifference(big), 0, "All missing large n");

        System.out.println("All tests passed.");
    }
}

