export function encodeText(text: string, key: number): string {
  // Validate text: must be a non-empty string
  if (typeof text !== 'string' || text.length === 0) {
    return 'Error: Invalid text input';
  }

  // Validate key: must be an integer number
  if (typeof key !== 'number' || !Number.isInteger(key)) {
    return 'Error: Invalid encryption key';
  }

  // Shift each UTF-16 code unit by the key. This keeps the function pure and
  // deterministic and avoids throwing on out-of-range Unicode code points.
  let result = '';
  for (let i = 0; i < text.length; i++) {
    const code = text.charCodeAt(i);
    const shifted = code + key;
    result += String.fromCharCode(shifted);
  }

  return result;
}

