import unittest
import random
from typing import Dict, Tuple

def minimize_max_run(s: str, numOps: int) -> int:
    """
    Compute the minimum possible length of the longest contiguous substring of identical
    characters after performing at most numOps single-bit flips on s.
    """
    n = len(s)
    if n == 0:
        return 0
    # Helper: check if we can achieve max run <= L with <= numOps flips
    def feasible(L: int) -> bool:
        if L >= n:
            return True
        # dp: map (char, run_len) -> min flips used up to current position
        # char is 0 or 1
        orig = int(s[0])
        dp: Dict[Tuple[int,int], int] = {}
        # two choices for first position
        dp[(orig, 1)] = 0
        dp[(1 - orig, 1)] = 1
        for i in range(1, n):
            c_orig = int(s[i])
            dp_next: Dict[Tuple[int,int], int] = {}
            for (pc, plen), flips in dp.items():
                # Choice: keep as c_orig (no flip)
                c = c_orig
                flips_new = flips
                if c == pc:
                    if plen < L:
                        key = (c, plen + 1)
                        dp_next[key] = min(dp_next.get(key, float('inf')), flips_new)
                    # else cannot keep because would exceed L
                else:
                    key = (c, 1)
                    dp_next[key] = min(dp_next.get(key, float('inf')), flips_new)
                # Choice: flip to 1 - c_orig
                c = 1 - c_orig
                flips_new = flips + 1
                if flips_new > numOps:
                    # prune: already exceed allowed flips
                    pass
                else:
                    if c == pc:
                        if plen < L:
                            key = (c, plen + 1)
                            dp_next[key] = min(dp_next.get(key, float('inf')), flips_new)
                        # else cannot flip here (would exceed L)
                    else:
                        key = (c, 1)
                        dp_next[key] = min(dp_next.get(key, float('inf')), flips_new)
            dp = dp_next
            if not dp:
                return False
            # small optimization: prune entries with flips > numOps
            dp = {k: v for k, v in dp.items() if v <= numOps}
            if not dp:
                return False
        # if any end state has flips <= numOps, feasible
        return min(dp.values()) <= numOps

    # Binary search minimal L in [1..n]
    lo, hi = 1, n
    while lo < hi:
        mid = (lo + hi) // 2
        if feasible(mid):
            hi = mid
        else:
            lo = mid + 1
    return lo


class TestMinimizeMaxRun(unittest.TestCase):
    def test_examples(self):
        self.assertEqual(minimize_max_run("000001", 1), 2)
        self.assertEqual(minimize_max_run("0000", 2), 1)
        self.assertEqual(minimize_max_run("0101", 0), 1)

    def test_edge_cases(self):
        # n = 1
        self.assertEqual(minimize_max_run("0", 0), 1)
        self.assertEqual(minimize_max_run("1", 1), 1)
        # numOps = 0 (no changes)
        self.assertEqual(minimize_max_run("000111000", 0), 3)
        # numOps = n (can flip arbitrarily)
        self.assertEqual(minimize_max_run("000111", 6), 1)

    def test_random_small_bruteforce(self):
        # For small n, brute-force all flip subsets up to numOps to verify
        def brute(s, numOps):
            n = len(s)
            best = n
            # iterate all subsets (2^n) but skip subsets with flips > numOps
            for mask in range(1 << n):
                if bin(mask).count("1") > numOps:
                    continue
                arr = list(s)
                for i in range(n):
                    if (mask >> i) & 1:
                        arr[i] = '1' if s[i] == '0' else '0'
                # compute longest run
                cur = 1
                mx = 1
                for j in range(1, n):
                    if arr[j] == arr[j-1]:
                        cur += 1
                        mx = max(mx, cur)
                    else:
                        cur = 1
                best = min(best, mx)
            return best

        for _ in range(50):
            n = random.randint(1, 12)
            s = ''.join(random.choice('01') for _ in range(n))
            numOps = random.randint(0, n)
            self.assertEqual(minimize_max_run(s, numOps), brute(s, numOps))

if __name__ == '__main__':
    unittest.main()

# Note:
# The algorithm binary-searches the minimal allowed maximum run length L and uses a
# dynamic programming feasibility check that tracks the minimal flips to reach each
# (last_bit, run_length) state. Time complexity is O(n * L) per feasibility check,
# so overall O(n * n * log n) worst-case, which is acceptable for n <= 1000.

