package Battery;

use strict;
use warnings;
use utf8;    # allow Unicode literals in source
use Exporter 'import';

our @EXPORT_OK = qw(get_battery_status);

# get_battery_status(status_string, percentage)
# Returns a string in the exact format: "<percentage>% <icon>"
# - percentage is used verbatim (no clamping or change)
# - icon is selected by the status string per the mapping in the specification
sub get_battery_status {
    my ($status, $level) = @_;

    # Icon mapping per requirements
    my %icons = (
        'Full'        => "",
        'Charging'    => "",
        'Discharging' => "",
    );

    my $icon = exists $icons{$status} ? $icons{$status} : "";

    return "$level% $icon";
}

1;


